import{c as t,Q as e,j as r,m as o}from"./chunks/framework.DpF7k2f3.js";const I=JSON.parse('{"title":"第1章 AIアプリ開発の真実","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part1-cognition/chapter1.md","filePath":"ja/part1-cognition/chapter1.md","lastUpdated":1779671667000}'),i={name:"ja/part1-cognition/chapter1.md"};function p(n,a,l,s,c,h){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="第1章-aiアプリ開発の真実" tabindex="-1">第1章 AIアプリ開発の真実 <a class="header-anchor" href="#第1章-aiアプリ開発の真実" aria-label="Permalink to &quot;第1章 AIアプリ開発の真実&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>この章を読む前は、AIアプリ開発は高すぎる壁に阻まれた分野だと思っていたかもしれません——PhDが必要、Transformerアーキテクチャの理解が必要、数学的素養が必要、と。</p><p>この章读完，你就会知道：</p><ul><li>AIアプリ開発とAI研究は別物であり、入門障壁は比較にならないほど異なる</li><li>2024-2026年に業界发生了什么变化、なぜ今が最佳のタイミングなのか</li><li>求人票の必要条件哪些是真的、哪些是虚的</li><li>異なる経歴の人々がどのように入社してきたか、8つの реальные案例</li></ul><hr><h2 id="_1-1-aiアプリ開発とは-ai研究・aiインフラとの違い" tabindex="-1">1.1 AIアプリ開発とは？（AI研究・AIインフラとの違い） <a class="header-anchor" href="#_1-1-aiアプリ開発とは-ai研究・aiインフラとの違い" aria-label="Permalink to &quot;1.1 AIアプリ開発とは？（AI研究・AIインフラとの違い）&quot;">​</a></h2><p>まず厳しい真実を言います：多くの人々が入りたいと思う「AI職」は、実際には彼らが思っているような「AI職」とは别なります。</p><h3 id="_3つの職種、一文字違い、天と地ほどの差" tabindex="-1">3つの職種、一文字違い、天と地ほどの差 <a class="header-anchor" href="#_3つの職種、一文字違い、天と地ほどの差" aria-label="Permalink to &quot;3つの職種、一文字違い、天と地ほどの差&quot;">​</a></h3><p>AI業界の技術ポジションを3層に分けます。自分のいる層を明確にすれば、道を間違えません：</p><p><strong>第1層：AI研究（Research）</strong></p><p>基礎革新を行う層。新モデルのトレーニング、Transformerアーキテクチャの改善、Attention機構の最適化。OpenAI、Google DeepMind、Anthropicの科学者たちが从事う的就是这项工作。</p><p>障壁有多高？这么说吧、この层实立つ人，全球范围内也就数万人レベルの顶尖人材。需要的是：学会論文、PhD学位（或同等科研能力）、扎实的数学功底、对最新論文了如指掌。</p><p>給与？天文数字。でも你我には关系ない。</p><p><strong>第2層：AIインフラ（Infrastructure）</strong></p><p>「上の層」のためのツールを作る層。トレーニングフレームワーク開発（PyTorch/TensorFlow保守）、推論エンジン最適化（vLLM/TensorRT）、分散トレーニングシステム、GPUクラスター管理。</p><p>障壁も同样に高い。システム底层、C++能力、深度学習フレームワークの原理を理解する必要がある。給与は研究岗よりやや低いが、それでも绝对是高薪。</p><p><strong>第3層：AIアプリ開発（Application）</strong></p><p>これがこの本が扱う内容です。也是你大概率能进去的那层。</p><p>簡単に言えば：既存のAI能力を使ってビジネス問題を解決する。具体的には：</p><ul><li>RAGシステムを構築して大規模モデルにプライベートナレッジベースへの回答を可能にする</li><li>Promptを書いてAIに 원하는形式出力を実現する</li><li>Agentを構築してAIに自动で多步骤タスクを実行させる</li><li>APIを对接してAI能力をプロダクトに集成する</li></ul><p>モデルのトレーニングは不要、逆伝播勾配の理解は不要、Attention公式の手導出も不要。必要なのは：<strong>既存のAI能力をビジネスシナリオに適用し、商業的価値を生み出すこと。</strong></p><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter1.html">中文版阅读</a></p></blockquote>',24)])])}const d=t(i,[["render",p]]);export{I as __pageData,d as default};
